export function shouldUseStaticData() {
  return import.meta.env.VITE_USE_REMOTE_API !== 'true';
}

export function getStaticComunas(region?: string, buscar?: string): Comuna[] {
  let comunas = [...(STATIC_REAL_DATA.comunas as unknown as Comuna[])];
  if (region) comunas = comunas.filter((c) => c.region.toLowerCase().includes(region.toLowerCase()));
  if (buscar) comunas = comunas.filter((c) => c.nombre.toLowerCase().includes(buscar.toLowerCase()));
  return comunas;
}

export function getStaticComuna(id: number | null): Comuna | null {
  if (!id) return null;
  return (STATIC_REAL_DATA.comunas as unknown as Comuna[]).find((c) => c.id === id) || null;
}

export function getStaticDashboard(comunaId: number | null): DashboardResumen | null {
  if (!comunaId) return null;
  return ((STATIC_REAL_DATA.dashboard as unknown as Record<string, DashboardResumen>)[String(comunaId)] || null);
}

export function getStaticHeatmap(comunaId: number | null) {
  if (!comunaId) return null;
  return ((STATIC_REAL_DATA.heatmap as Record<string, any>)[String(comunaId)] || null);
}

export function getStaticDelitos(filters: FilterState): Delito[] {
  if (!filters.comunaId) return [];
  let delitos = [...(((STATIC_REAL_DATA.delitos as unknown as Record<string, Delito[]>)[String(filters.comunaId)] || []))];
  if (filters.tipoDelito) delitos = delitos.filter((d) => d.tipo_delito === filters.tipoDelito);
  if (filters.fechaDesde) delitos = delitos.filter((d) => !d.fecha_hora || d.fecha_hora >= filters.fechaDesde!);
  if (filters.fechaHasta) delitos = delitos.filter((d) => !d.fecha_hora || d.fecha_hora <= filters.fechaHasta!);
  return delitos;
}

export function getStaticTiposDelito(): string[] {
  return [...STATIC_REAL_DATA.tipos];
}

export function getStaticRanking() {
  return Object.values(STATIC_REAL_DATA.dashboard).map((item: any) => ({
    comuna_id: item.comuna.id,
    nombre_comuna: item.comuna.nombre,
    region: item.comuna.region,
    indice_global: item.kpi.indice_global,
    ranking_nacional: item.kpi.ranking_nacional,
    tendencia: item.kpi.tendencia_anual,
    tasa_delictual: item.estadisticas_delitos.tasa_100k,
  })).sort((a: any, b: any) => (b.indice_global || 0) - (a.indice_global || 0));
}

export function getStaticGeorefQuality(comunaId: number | null, dias: number) {
  const dashboards = Object.values(STATIC_REAL_DATA.dashboard as unknown as Record<string, DashboardResumen>)
    .filter((item: any) => !comunaId || item.comuna.id === comunaId);
  const comunas = dashboards.map((item: any) => ({
    comuna_id: item.comuna.id,
    codigo_ine: getStaticComuna(item.comuna.id)?.codigo_ine,
    nombre_comuna: item.comuna.nombre,
    dias,
    total_registros: item.calidad_datos?.total_registros || 0,
    exacta: 0,
    sector: item.calidad_datos?.total_registros || 0,
    comuna: 0,
    sin_senal: 0,
    coordenadas_invalidas: 0,
    porcentajes: { exacta: 0, sector: 100, comuna: 0, sin_senal: 0 },
    puntaje_calidad: 65,
    nivel_calidad: 'media',
    modo_predominante: 'sector',
    sectores_detectados: [],
    recomendaciones: ['Mantener sector, barrio o cuadrante en las nuevas cargas para mejorar la precisi?n territorial.'],
  }));
  const total = comunas.reduce((sum, item) => sum + item.total_registros, 0);
  return {
    dias,
    total_comunas: comunas.length,
    resumen: {
      total_registros: total,
      exacta: 0,
      sector: total,
      comuna: 0,
      sin_senal: 0,
      coordenadas_invalidas: 0,
      puntaje_calidad: total ? 65 : 0,
      nivel_calidad: total ? 'media' : 'sin_datos',
      porcentajes: { exacta: 0, sector: total ? 100 : 0, comuna: 0, sin_senal: 0 },
    },
    comunas,
  };
}

